const items = $input.all();

for (const item of items) {
  const ragOutput = item.json.aiAgent?.retrievals || [];

  const lowScoreDocs = ragOutput.filter(doc => 
    doc.metadata?.score && doc.metadata.score < 0.7
  );

  if (lowScoreDocs.length > 0) {
    throw new Error(`Low retrieval quality: ${lowScoreDocs.length} docs below 0.7 score threshold`);
  }
}

return items;

const currentTime = Date.now();
const items = $input.all();

for (const item of items) {
  const memoryContext = item.json.memory || [];
  const staleDocs = memoryContext.filter(doc => 
    doc.metadata?.timestamp && 
    (currentTime - doc.metadata.timestamp) > 300000 // 5 minutes
  );

  if (staleDocs.length > 2) {
    return [{ 
      json: { 
        error: 'STALE_CONTEXT', 
        count: staleDocs.length,
        docs: staleDocs.map(d => d.metadata.timestamp)
      }
    }];
  }
}

return items;

function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

const items = $input.all();
const oversized = [];

for (const item of items) {
  const doc = item.json.document;
  if (!doc) continue;

  const tokenCount = estimateTokens(doc.content);
  if (tokenCount > 800) {
    oversized.push({ id: doc.id, tokens: tokenCount, content: doc.content.slice(0, 100) + '...' });
  }
}

if (oversized.length > 0) {
  throw new Error(`Oversized chunks detected: ${oversized.length} docs >800 tokens`);
}

return items;

