// Code node after AI Agent - Dynamic RAG Filter
const items = $input.all();
const filtered = [];

for (const item of items) {
  let retrievals = item.json.aiAgent?.retrievals || [];

  // Filter to high-quality docs only
  retrievals = retrievals.filter(doc => doc.metadata?.score >= 0.75);

  if (retrievals.length === 0) {
    // Fallback: loosen threshold slightly
    retrievals = item.json.aiAgent?.retrievals?.filter(doc => doc.metadata?.score >= 0.65) || [];
  }

  item.json.filteredRetrievals = retrievals;
  filtered.push(item);
}

return filtered;

const items = $input.all();
const TWO_MINUTES = 120000;
const now = Date.now();

for (const item of items) {
  if (item.json.memory) {
    item.json.memory = item.json.memory.filter(doc => 
      now - (doc.metadata?.timestamp || 0) < TWO_MINUTES
    );
  }

  // Add query metadata for freshness tracking
  item.json.queryTimestamp = now;
}

return items;

function chunkDocument(content: string, maxTokens: number = 750): string[] {
  const words = content.split(' ');
  const chunks: string[] = [];
  let currentChunk = '';

  for (const word of words) {
    const testChunk = currentChunk + ' ' + word;
    if (estimateTokens(testChunk) > maxTokens) {
      if (currentChunk) chunks.push(currentChunk.trim());
      currentChunk = word;
    } else {
      currentChunk = testChunk;
    }
  }
  if (currentChunk) chunks.push(currentChunk.trim());

  return chunks;
}

function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

const items = $input.all();
const chunkedItems = [];

for (const item of items) {
  const content = item.json.document?.content;
  if (content && estimateTokens(content) > 750) {
    const chunks = chunkDocument(content);
    chunks.forEach((chunk, i) => {
      chunkedItems.push({
        json: {
          ...item.json.document,
          content: chunk,
          chunkIndex: i,
          totalChunks: chunks.length
        }
      });
    });
  } else {
    chunkedItems.push(item);
  }
}

return chunkedItems;

