import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  webhookToken: $secrets.vexToken,
  framework: 'n8n',
  detectors: ['rag-quality', 'context-staleness', 'chunk-size']
});

// Run after every AI Agent node
const result = await vex.validate($input.first().json);

if (!result.passed) {
  // Auto-apply best fix
  const fixNode = result.recommendedFix;

  return [{
    json: {
      vexReport: result,
      autoFix: fixNode.code,
      qualityScore: result.score,
      failedChecks: result.failures
    }
  }];
}

// Pass through if healthy
return $input.all();
